module.render:
    const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
    const leftTitle = args.left_title || 'A';
    const rightTitle = args.right_title || 'B';
    const colorLeft = args.color_left || '#95a5a6';
    const colorRight = args.color_right || 'var(--accent-color)';
    const vs = (args.vs !== undefined && String(args.vs) !== '') ? esc(String(args.vs)) : 'VS';
    const badgeColor = args.badge_color || '#333';
    const dir = String(args.layout || 'side').toLowerCase() === 'stacked' ? 'column' : 'row';
    const radius = args.radius || '8px';
    const leftContent = sections[0] ? sections[0].trim() : '';
    const rightContent = sections[1] ? sections[1].trim() : '';
    return `\n\n
<div class="mdp-mod-compare" style="flex-direction: ${dir};">
<div class="mdp-compare-col mdp-compare-left" style="--comp-color: ${colorLeft}; --comp-radius: ${radius};">
<div class="mdp-compare-header">${leftTitle}</div>
<div class="mdp-compare-body">

${leftContent}

</div>
</div>
<div class="mdp-compare-vs" style="background: ${badgeColor};">${vs}</div>
<div class="mdp-compare-col mdp-compare-right" style="--comp-color: ${colorRight}; --comp-radius: ${radius};">
<div class="mdp-compare-header">${rightTitle}</div>
<div class="mdp-compare-body">

${rightContent}

</div>
</div>
</div>
\n\n`;
